import React from "react";
import "./nav.css";

function Nav() {
  const [isActive, setIsActive] = React.useState(false);
  const handleClick = () => {
    setIsActive((current) => !current);
  };
  return <div onClick={handleClick} className="gg-menu-grid-o"></div>;
}

export default Nav;

